// API Base URL - Django Backend
const API_BASE = '/api';

// Generic fetch wrapper with axios-like interface
const api = {
  get: async (endpoint) => {
    const response = await fetch(API_BASE + endpoint, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
    });
    if (!response.ok) throw new Error('API Error: ' + response.status);
    return response.json();
  },

  post: async (endpoint, data) => {
    const response = await fetch(API_BASE + endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    if (!response.ok) throw new Error('API Error: ' + response.status);
    return response.json();
  },

  patch: async (endpoint, data) => {
    const response = await fetch(API_BASE + endpoint, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    if (!response.ok) throw new Error('API Error: ' + response.status);
    return response.json();
  },

  delete: async (endpoint) => {
    const response = await fetch(API_BASE + endpoint, {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
    });
    if (!response.ok) throw new Error('API Error: ' + response.status);
    return response.json();
  },
};

// Legacy API exports for backward compatibility
export const devicesApi = {
  list: () => api.get('/devices/'),
  save: (data) => api.post('/devices/', data),
  delete: (id) => api.delete('/devices/' + id + '/'),
  dashboard: () => api.get('/devices/dashboard/'),
  runBackup: (deviceId) => api.post('/backups/', { device_id: deviceId }),
  backups: (deviceId) => api.get('/backups/?device_id=' + deviceId),
};

export const auditApi = {
  list: (filters = {}) => {
    const params = new URLSearchParams(filters).toString();
    return api.get('/audit-logs/?' + params);
  },
};

export default api;
